Real64 rotAzmDiffDeg(Real64 AzmA, Real64 AzmB)
{
    // This function takes two (azimuth) angles in Degree(s),
    // and returns the rotational angle difference in Degree(s).

    Real64 diff = AzmB - AzmA;
    if (diff > 180.0) {
        diff = 360.0 - diff;
    } else if (diff < -180.0) {
        diff = 360.0 + diff;
    }
    return std::abs(diff);
}

